A large bowl can hold $3.5$ pints. A smaller bowl can hold less than $80\%$ of this amount. Graph the possible amounts, in quarts, that can be held by the smaller bowl.

\begin{tikzpicture}
\draw[<->] (-0.5,0) -- (6.5,0);
\foreach \x/\label in {0/0.95, 0.5/1, 1/1.05, 1.5/1.1, 2/1.15, 2.5/1.2, 3/1.25, 3.5/1.3, 4/1.35, 4.5/1.4, 5/1.45, 5.5/1.5}
  \draw (\x,0.1) -- (\x,-0.1) node[below] {\footnotesize \label};
\end{tikzpicture}
